import{c as r,Q as t,j as e,m as o}from"./chunks/framework.CQqJojvj.js";const c=JSON.parse('{"title":"16 - 智力题","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/16-brain-teasers.md","filePath":"bagu/16-brain-teasers.md","lastUpdated":null}'),l={name:"bagu/16-brain-teasers.md"};function n(i,a,s,h,d,p){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="_16-智力题" tabindex="-1">16 - 智力题 <a class="header-anchor" href="#_16-智力题" aria-label="Permalink to &quot;16 - 智力题&quot;">​</a></h1><blockquote><p>智力题在大厂面试中偶尔出现，主要考察逻辑思维和分析问题的能力。</p></blockquote><hr><h2 id="_1-经典智力题" tabindex="-1">1. 经典智力题 <a class="header-anchor" href="#_1-经典智力题" aria-label="Permalink to &quot;1. 经典智力题&quot;">​</a></h2><h3 id="赛马问题" tabindex="-1">赛马问题 <a class="header-anchor" href="#赛马问题" aria-label="Permalink to &quot;赛马问题&quot;">​</a></h3><p><strong>题目：</strong> 25 匹马，每次最多 5 匹比赛，找出前 3 名，最少需要几场比赛？</p><p><strong>答案：</strong> 7 场。</p><p><strong>思路：</strong></p><ol><li>分 5 组，每组 5 匹比赛（5 场）</li><li>每组第一名比赛，决出最快的一匹（1 场）</li><li>最快马所在组的前 3 名 + 第二名所在组的前 2 名 + 第三名所在组的第 1 名（共 5 匹）再比一次（1 场）</li><li>第 7 场比赛的前 3 名即最终结果</li></ol><h3 id="天平称重" tabindex="-1">天平称重 <a class="header-anchor" href="#天平称重" aria-label="Permalink to &quot;天平称重&quot;">​</a></h3><p><strong>题目：</strong> 12 个球，其中 1 个重量不同（不知轻重），用天平称 3 次找出。</p><p><strong>思路：</strong> 分 3 组（4, 4, 4），首次称两组：</p><ul><li>平衡 → 异常球在第 3 组，用标准球对比</li><li>不平衡 → 异常球在 8 个中，根据天平倾斜判断轻重</li></ul><h3 id="扔鸡蛋" tabindex="-1">扔鸡蛋 <a class="header-anchor" href="#扔鸡蛋" aria-label="Permalink to &quot;扔鸡蛋&quot;">​</a></h3><p><strong>题目：</strong> 2 个鸡蛋，100 层楼，找到鸡蛋不碎的最高楼层，最少需要几次？</p><p><strong>答案：</strong> 14 次。</p><p><strong>思路：</strong> 第一个鸡蛋决定区间，第二个鸡蛋在区间内线性尝试。最优策略是让每多扔一次鸡蛋 1，鸡蛋 2 的尝试次数少 1 次。所以第一个间隔从 14 开始，依次 13、12...，和为 105 &gt; 100。即：14 → 27 → 39 → 50 → 60 → 69 → 77 → 84 → 90 → 95 → 99 → 100。</p><h3 id="烧绳子" tabindex="-1">烧绳子 <a class="header-anchor" href="#烧绳子" aria-label="Permalink to &quot;烧绳子&quot;">​</a></h3><p><strong>题目：</strong> 两根不均匀的绳子，每根烧完 1 小时，如何测量 45 分钟？</p><p><strong>答案：</strong> 第一根两头同时点（30 分钟烧完），同时第二根点一头。第一根烧完时（30 分钟已过）立即将第二根的另一头也点燃，第二根剩余部分将在 15 分钟内烧完。30 + 15 = 45 分钟。</p><hr><h2 id="_2-概率题" tabindex="-1">2. 概率题 <a class="header-anchor" href="#_2-概率题" aria-label="Permalink to &quot;2. 概率题&quot;">​</a></h2><h3 id="囚徒开关问题" tabindex="-1">囚徒开关问题 <a class="header-anchor" href="#囚徒开关问题" aria-label="Permalink to &quot;囚徒开关问题&quot;">​</a></h3><p><strong>题目：</strong> 100 个囚徒，1 个房间有电灯（初始关）。每天随机 1 个囚徒进房间，可以选择开/关灯。只要有 1 个囚徒能说出&quot;所有囚徒都进过房间至少一次&quot;，所有人释放。商量策略。</p><p><strong>思路：</strong> 指定 1 人计数，其他人每人第一次进房间且灯关着时开灯（只开一次）。计数的人每次进房间灯开着就计数+1 并关灯。计数到 99 即知所有人都进过。</p><h3 id="生男生女概率" tabindex="-1">生男生女概率 <a class="header-anchor" href="#生男生女概率" aria-label="Permalink to &quot;生男生女概率&quot;">​</a></h3><p><strong>题目：</strong> 一个国家所有家庭都生育直到生出男孩为止。长期后男女比例？</p><p><strong>答案：</strong> 1:1。因为每次生育是独立事件，男/女概率始终是 1/2。家庭生育策略不影响整体的期望比例。</p><hr><h2 id="_3-逻辑推理" tabindex="-1">3. 逻辑推理 <a class="header-anchor" href="#_3-逻辑推理" aria-label="Permalink to &quot;3. 逻辑推理&quot;">​</a></h2><h3 id="帽子颜色" tabindex="-1">帽子颜色 <a class="header-anchor" href="#帽子颜色" aria-label="Permalink to &quot;帽子颜色&quot;">​</a></h3><p><strong>题目：</strong> 3 个人，帽子颜色可能是红或蓝（至少 1 红）。每个人能看到其他两人帽子但看不到自己的。依次回答自己帽子的颜色。</p><p><strong>思路：</strong></p><ul><li>第 1 人回答不出 → 他看到至少 1 顶红帽</li><li>第 2 人回答不出 → 他看到至少 1 顶红帽（不含第 1 人看到的可能）</li><li>第 3 人推断：如果他的帽子是蓝的，第 2 人会推断出自己是红的（因为第 1 人看到 1 顶红帽）→ 第 2 人没回答，说明第 3 人是红的。</li></ul><hr><h2 id="_4-估算题" tabindex="-1">4. 估算题 <a class="header-anchor" href="#_4-估算题" aria-label="Permalink to &quot;4. 估算题&quot;">​</a></h2><h3 id="北京有多少个加油站" tabindex="-1">北京有多少个加油站？ <a class="header-anchor" href="#北京有多少个加油站" aria-label="Permalink to &quot;北京有多少个加油站？&quot;">​</a></h3><p><strong>思路：</strong></p><ol><li>北京面积 ≈ 16410 km²</li><li>假设城区占 20%，即 3282 km²</li><li>加油站服务半径约 2km²一个</li><li>城区加油站 ≈ 3282 / 2 ≈ 1641 座</li><li>加上郊区，总共约 2000-2500 座</li></ol><p><strong>关键：不是追求精确结果，而是展现合理的估算思路。</strong></p>',40)])])}const g=r(l,[["render",n]]);export{c as __pageData,g as default};
